var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으응...","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"늦잠이야. 한참 기다렸어.","JPN":"お寝坊さん。ずいぶん待ったのよ。","ENG":"You sure sleep in. I've been waiting a while.","TWN":"睡過頭了，我等你好久了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...음?","JPN":"……ん？","ENG":"...Mm?","TWN":"……嗯？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"히익-!","JPN":"ひいっ！","ENG":"Eek...!","TWN":"咿—！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"놀래킨 적 없는데.","JPN":"驚かしてないのに。","ENG":"I didn't do anything to startle you.","TWN":"我又沒嚇你。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그야 네놈이 흉악하게 생겨 먹지 않았느냐.","JPN":"それはお前が凶悪な顔をしているからであろう。","ENG":"Well, that's because you look vicious.","TWN":"那是因為你長得太兇了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"실례네. 너도 뿔 달고 있는 주제에.","JPN":"失礼ね。あなただって角が生えてるくせに。","ENG":"Rude. Says the one with horns.","TWN":"真失禮，你自己還長著角呢。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...으익! 이 몸에게 무슨 짓을 한 것이냐! 여긴 또 어디고!","JPN":"……ぐぎぎっ！　吾輩に何をした！　ここはどこだ！","ENG":"...Ghk! What did you do to me?! And where is this place?!","TWN":"……唔！你對我做了什麼！這裡又是什麼地方！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"여긴, <color=#ffd34c>감옥</color>이야.","JPN":"ここは、<color=#ffd34c>牢獄</color>だよ。","ENG":"This is a <color=#ffd34c>prison</color>.","TWN":"這裡是<color=#ffd34c>監獄</color>。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"일단은 널 빼앗은 입장이니까. 아무 데나 풀어둘 수는 없거든.","JPN":"一応はあなたを奪った立場だから。自由にさせておくわけにもいかないのよ。","ENG":"For now, I did steal you away. I can't exactly let you run loose anywhere you want.","TWN":"畢竟我算是把你奪走的人，總不能隨便放你出去。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"감옥은 싫다! 날 내보내거라!","JPN":"牢獄はイヤだぞ！　吾輩を解放しろ！","ENG":"I hate prisons! Let me out!","TWN":"我討厭監獄！快放我出去！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"싫다면?","JPN":"嫌だと言ったら？","ENG":"And if I refuse?","TWN":"如果我說不要呢？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으기이이익...!","JPN":"ぐぬぬぬぬっ……！","ENG":"Grrr...!","TWN":"唔唔唔……！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"사실 넌 이곳에 갇혀있는 게 아니야. 원한다면 얼마든지 이곳을 나갈 수 있어.","JPN":"実は、あなたをここに閉じ込めているわけじゃないの。望めばいくらでもここから出られるよ。","ENG":"Actually, you aren't trapped here.","TWN":"其實你並沒有被關起來。只要你願意，隨時都可以離開這裡。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"네가 나의 일부라는 사실을 받아들이기만 한다면 말이야.","JPN":"あなたが私の一部だっていう事実を受け入れればね。","ENG":"You can leave this place whenever you want. As long as you accept that you are a part of me.","TWN":"只要你接受你是我的一部分這件事。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그게... 무슨 소리인 것이냐?","JPN":"それは……どういうことだ？","ENG":"What... are you talking about?","TWN":"那……那是什麼意思？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸이 네 녀석과 같을 리 없지 않더냐!","JPN":"この吾輩がお前と一緒なわけないであろう！","ENG":"There's no way I could be the same as you!","TWN":"我怎麼可能和你一樣！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"넌 마왕이잖아. 그렇지?","JPN":"あなたは魔王でしょう？　違うの？","ENG":"You're a Demon Lord, aren't you?","TWN":"你是魔王吧？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸은 마왕이다.","JPN":"吾輩は魔王である。","ENG":"I am a Demon Lord.","TWN":"沒錯，我就是魔王。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"하지만, 이 몸은 네놈처럼...","JPN":"だが、吾輩はお前のように……","ENG":"But I don't...","TWN":"但是我不像你……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...너처럼 사람을 해치면서 웃지 않아!!","JPN":"……お前のように人を傷つけながら笑わん！！","ENG":"...laugh while hurting people like you do!!","TWN":"……不像你那樣，一邊傷害人一邊笑！！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 소녀의 몸. 아발론의 작은 왕은 어린 나이에 요절할 운명을 타고났어.","JPN":"その少女の体。アバロンの小さな王は早世する運命だった。","ENG":"That flesh. Avalon's little queen was born fated to die young.","TWN":"那個少女的身體是阿瓦隆的小王，她本來注定會在年幼時早逝。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 악마는 그녀의 영혼을 구하기 위해, 내 일부를 융합해 그 운명을 비틀었지.","JPN":"でも悪魔は彼女の魂を救うために、私の一部を融合してその運命を捻じ曲げたの。","ENG":"But to save her soul, a demon fused part of me into her and twisted that fate.","TWN":"但惡魔為了拯救她的靈魂，融合了我的一部分，扭曲了那個命運。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"악마는 가짜다. 그런 건 본 적도 없느니라.","JPN":"悪魔など偽物だ。そのようなもの、見たこともない。","ENG":"The demon is a fake. I've never seen such a thing.","TWN":"惡魔是假的，我從沒見過。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아니. 넌 누구보다 그 악마를 잘 알아.","JPN":"いいえ。あなたは誰よりもその悪魔のことをよく知ってるよ。","ENG":"No. You know that demon better than anyone.","TWN":"不，你比任何人都清楚那個惡魔。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 악마는 네가 있던 세계에서... 그레모리라는 이름으로 불렸거든.","JPN":"その悪魔はあなたのいた世界で……グレモリーという名前で呼ばれていたから。","ENG":"In the world you were in... that demon goes by the name Gremory.","TWN":"在你所在的世界，那個惡魔被稱為……葛茉莉。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"넌 본래 죽었어야 할 소녀의 몸에 갇혀 있던, 마왕의 파편이야.","JPN":"あなたは本来死ぬべきだった少女の体に閉じ込められていた、魔王の破片。","ENG":"You are a Fragment of a Demon Lord, trapped inside the body of a girl who was supposed to die.","TWN":"你只是被困在一個本該死去的少女體內的魔王碎片。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 악마가 우릴 이용한 거라고.","JPN":"悪魔が私たちを利用したのよ。","ENG":"That demon used us.","TWN":"那個惡魔一直在利用我們。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그, 그럴 리가 없다.","JPN":"そ、そんなわけない。","ENG":"Th-that can't be.","TWN":"不、不可能。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그레모리는 날 이용한 게 아니라, 이 몸의 충실한 하수인...","JPN":"グレモリーは吾輩を利用したのではなく、吾輩の忠実な下僕……","ENG":"Gremory didn't use me. She is my loyal servant...","TWN":"葛茉莉不是利用我，她是我忠誠的部下……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"넌 마왕이 아니라 임금님이야.","JPN":"あなたは魔王じゃなくて、王様よ。","ENG":"You're not a Demon Lord. You're a queen.","TWN":"你不是魔王，你只是國王而已。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"뭐, 자길 뭐라고 부르든 네 마음이겠지만.","JPN":"まあ、自分のことをどう呼ぼうがあなたの自由でしょうけど。","ENG":"Well, call yourself whatever you want.","TWN":"不過隨你高興怎麼稱呼自己。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...그럴 리가...","JPN":"……そんな……","ENG":"...That can't...","TWN":"……不可能……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 악마가 원하는 건 작은 왕이지, 네가 아냐.","JPN":"あの悪魔が望んでいるのは小さな王で、あなたじゃないの。","ENG":"What that demon wants is the little queen, not you.","TWN":"那個惡魔想要的是我，不是你。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 네가 없으면, 반쪽짜리 영혼을 가진 작은 왕은 영원히 깨어날 수 없겠지.","JPN":"でもあなたがいないと、不完全な魂を持つ小さな王は永遠に目覚められないでしょうね。","ENG":"But without you, the little queen, with only half a soul, can never awaken.","TWN":"但如果沒有你，只有半個靈魂的我永遠也無法甦醒。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그때 그 악마는 뭘 원할까? 너? 아니면...","JPN":"その時、あの悪魔は何を望むと思う？　あなた？　それとも……","ENG":"When that time comes, what do you think the demon will want? You? Or...","TWN":"那麼，那個惡魔真正想要的是什麼？是你？還是……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"임금님을 움직이게 하는, 너라는 조각?","JPN":"王様を動かすための、あなたという破片？","ENG":"...the Fragment you are that lives in the little majesty?","TWN":"那個被稱作你，能夠驅動國王的碎片？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"시끄럽구나!","JPN":"うるさい！","ENG":"Silence!","TWN":"閉嘴！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...듣기 싫도다. 그런 말은.","JPN":"……聞きたくないのだ。そういう話は。","ENG":"...I don't want to hear that. Not from you.","TWN":"……我不想聽這種話。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"정말이지 나약하구나.","JPN":"本当に弱いんだね。","ENG":"You really are weak.","TWN":"真軟弱。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 걱정 마.","JPN":"でも心配しないで。","ENG":"But don't worry.","TWN":"不過別擔心。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그들이 널 원치 않아도, 우리에겐 네가 필요하니까.","JPN":"彼らがあなたを望まなくても、私たちにはあなたが必要だから。","ENG":"Even if they don't want you, we need you.","TWN":"就算他們不需要你，我們仍然需要你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"휴우-","JPN":"ふう……","ENG":"Phew...","TWN":"呼—"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"대균열을 닫았다는 사실이 무색할 정도로 침식체들은 쉴 틈 없이 쏟아지는군요.","JPN":"大亀裂を塞いだという事実が恥ずかしくなるほど、侵食体が絶え間なく湧き出てきますね。","ENG":"For something that supposedly closed the Grand Dimension Crevice, C.O.s are still pouring out nonstop.","TWN":"明明已經關閉大峽谷，侵蝕體依然源源不絕湧出。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"세피라의 권능으로 틀어 막은 건 여섯 대균열 중 하나일 뿐이야.","JPN":"セフィラの権能で塞いだのは6つの大亀裂のうちの1つだけだ。","ENG":"What Sephira's power sealed off was only one of the six Grand Dimension Crevices.","TWN":"用塞菲拉的權能封印的，只是六個大峽谷中的一個。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"남은 다섯 대균열은 고장 난 수도꼭지처럼, 여전히 세계라는 수조를 허수 에너지로 가득 채워가고 있지.","JPN":"残りの5つの大亀裂は壊れた蛇口のように、相変わらず世界という水槽を虚数エネルギーで満たそうとしている。","ENG":"The remaining five Grand Dimension Crevices are still filling up the reservoir called the world with Imaginary Energy like broken faucets.","TWN":"剩下的五個大峽谷就像壞掉的水龍頭，不停把虛空能量注入這個名為世界的水槽。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그 수조가 가득 차면 어떤 일이 벌어지는 걸까요?","JPN":"その水槽が満タンになると、どんなことが起きるんでしょうか？","ENG":"What happens once that reservoir fills up?","TWN":"等水槽被填滿，會發生什麼事？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 현실이, 이면세계와 똑같은 환경으로 변하겠죠.","JPN":"この現実が、裏世界と同じ環境になるでしょう。","ENG":"This reality will turn into the same environment as the Counterside.","TWN":"這個現實世界，將會變成和異界一樣的環境。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관리국과 그 밖의 전력이 할 수 있는 최선은, 박힌 침식쐐기들을 뽑아내며 그 진전을 늦추는 것 뿐입니다.","JPN":"管理局とその他の戦力にできる最善は、刺さっている侵食楔を抜き取りながらその進展を遅らせることだけです。","ENG":"The best the Administration and the rest of our forces can do is slow that progress by pulling out the embedded Corrupted Wedges.","TWN":"管理局與其他戰力能做到的，也只是拔除那些侵蝕楔子、延緩進展而已。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"...달님 분들이 무사히 임무를 마치길 기다리면서 말이죠.","JPN":"……お月様チームの皆さんが無事任務を終えることを待ちながら、ですよね。","ENG":"...While we wait for Team Moon to safely complete their mission.","TWN":"……一邊等待月亮順利完成任務。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"현실에서 출발한 지 4시간 지났으니까- 달님 팀 기준으로는 한 열흘 정도 흘렀겠네.","JPN":"現実から出発して4時間過ぎてるから……お月様チームからすると10日くらい経ってるかな？","ENG":"It's been four hours since they departed from our reality, so for Team Moon, that means about ten days have passed by now.","TWN":"從現實出發已經過了4小時—以月亮小隊的時間來算，大概過了十天吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"열흘이라니, 시간 참 빠르네요. 상대성 이론이란 거죠?","JPN":"10日って、時間が流れるのがずいぶん早いんですね。相対性理論というものでしょうか？","ENG":"Ten days? Time really flies. That's relativity, right?","TWN":"十天啊，時間過得真快。這就是相對論吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"응-! 힐데 씨도 돌아올 때쯤이면 키가 한 뼘 자라있을 지도?","JPN":"うん！　ヒルデさんも戻ってくる頃には少しは背が伸びてるかも？","ENG":"Yep! By the time Hilde gets back, she might've grown another handspan taller.","TWN":"嗯—！等希爾德回來時，說不定還會長高一點呢？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 스승님의 성장기는 이미 지난 걸로 알고 있습니다만...","JPN":"ハハ、師匠の成長期はとっくに終わってると思いますけど……","ENG":"Haha, as far as I know, Master is already past her growing years...","TWN":"哈哈，我記得師父的成長期早就結束了……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"상대성 이론의 마법이 닫힌 성장판도 열어준다면 가능성이 있으려나?","JPN":"相対性理論の魔法が、すでに閉じてしまった成長板を復活させてくれるなら可能性がありますかね？","ENG":"Though if the magic of relativity could reopen closed growth plates, maybe there's a chance.","TWN":"如果相對論的魔法能讓閉合的生長板重新打開，或許還有機會？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"시윤 군, 이 무전 내용은 전부 기록으로 남고 있어요.","JPN":"シリュウ君、この無線はすべて記録に残ります。","ENG":"Shiyoon, all of this radio chatter is being recorded.","TWN":"時雲，你的無線電內容全部都會留下記錄。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"수연이는 이걸 빌미로 시윤 군을 협박하고도 남을 사람이라고요.","JPN":"キズナならこれを口実にシリュウ君を脅迫するかもしれませんよ。","ENG":"And Sooyeon is exactly the kind of person who'd use this as leverage to threaten you.","TWN":"秀妍可是會拿這些威脅你的人。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그때가 되면 같이 해명 좀 부탁 드릴게요, 베스카 씨.","JPN":"その時になったら、一緒に弁解をお願いしますね、ベスカーさん。","ENG":"When that happens, I'll be counting on you to help explain things, Vesca.","TWN":"到時候請你幫我一起解釋一下吧，貝斯卡。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"아하항- 그럼 그럼. 초코파이 사 들고 달래주면 되는 거지? 힐데 씨라면 분명 단 거 좋아할 테니까-","JPN":"あははーもちろんだよ。チョコパイでなだめたらいいんだよね？　ヒルデさんは甘いものが好きそうだもんね～","ENG":"Ahaha, sure, sure. I just need to buy some chocolate snacks and calm her down, right? Hilde would definitely like sweets...","TWN":"啊哈哈—那就買巧克力派哄她吧？希爾德看起來一定很喜歡甜食。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"...이 시련은 베스카 씨의 안전을 위해서라도 저 혼자 감내하는 편이 낫겠네요.","JPN":"……この試練はベスカーさんの身の安全のためにも僕一人で甘受した方がよさそうですね。","ENG":"...For your own safety, Vesca, I think this is one ordeal I'd better endure alone.","TWN":"……為了貝斯卡的安全，我還是自己承受這場試煉比較好。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시답잖은 농담은 그쯤 해두시죠.","JPN":"くだらない冗談はそこまでにしてください。","ENG":"That's enough of the pointless joking.","TWN":"閒聊就到此為止。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"방금 전부터 구조물 침식화로 추정되는 재난 신고가 곳곳에서 접수되고 있습니다.","JPN":"先程から構造物の侵食化と推定される災難通報が方々から来ています。","ENG":"Reports of disasters believed to be caused by structure Corruption have been coming in from all over since just now.","TWN":"從剛才開始，各地陸續接到通報發生疑似建築侵蝕化的災害。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"신고 내용은, 건물이 살아 움직인다... 아마 그런 거겠지.","JPN":"通報内容は、建物が生き物のように動く……おそらくそんなものだろう。","ENG":"The reports are probably saying buildings are starting to move on their own... something like that.","TWN":"通報內容應該是……建築物在動吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그런 건, 침식파를 쬐는 정도론 일어날 수 없는 일처럼 들리는데요?","JPN":"侵食波を浴びるくらいでは起こり得ない事態のように聞こえるんですが。","ENG":"That sounds like something far beyond what mere exposure to a Corruption ray should cause, doesn't it?","TWN":"光是被侵蝕波照射，應該不至於發生那種事吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"무기물의 침식체화는 이면세계에서 관측되는 대표적인 사례죠.","JPN":"無機物の侵食体化は裏世界で観測される代表的な事例です。","ENG":"The Corruption of inorganic matter into C.O.s is one of the representative cases observed in the Counterside.","TWN":"無機物變成侵蝕體，在異界是很常見的現象。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"현실이 이면세계로 변해가고 있다는, 가장 또렷한 증거입니다.","JPN":"現実が裏世界化しつつあるという、一番明確な証拠です。","ENG":"It's the clearest sign yet that reality is turning into the Counterside.","TWN":"這正是現實逐漸變成異界的最明顯證據。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"진짜 코앞까지 왔구나. 세계 멸망.","JPN":"本当に目前まで来てるんだね。世界の滅亡が。","ENG":"So it's really right up in our faces now. The end of the world.","TWN":"世界末日真的近在眼前了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"어쩌겠어요.","JPN":"仕方ありませんよ。","ENG":"What can we do?","TWN":"那又怎樣？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"세상이 내일 망해도, 오늘 침식체 하나 더 베는 게 저희 사명인 걸요.","JPN":"明日世界が滅ぶとしても、今日1体でも多く侵食体を斬るのが僕たちの使命なんですから。","ENG":"Even if the world ends tomorrow, our duty today is still to cut down one more C.O.","TWN":"就算世界明天毀滅，我們今天的使命依然是多斬除一個侵蝕體。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"주한, 우물의 진척은 어때?","JPN":"シスイ、イドの進行状況はどう？","ENG":"Joo Han, how's the Well coming along?","TWN":"周翰，井的進度怎麼樣？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L41_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"몇 번 위기가 있긴 했지만, 덕분에 잘 되어가고 있어요.","JPN":"何度か危機はありましたが、おかげさまでうまくいっています。","ENG":"There were a few close calls, but thanks to all of you, it's progressing well.","TWN":"雖然有幾次危機，不過多虧大家，目前進展順利。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"이대로라면 기한보다 일찍 완성할 것 같아요.","JPN":"このまま行けば期限よりも早く完成させられそうです。","ENG":"At this rate, I think we'll finish ahead of schedule.","TWN":"照這樣下去，應該能在期限內完成。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신이 천재라서?","JPN":"あなたが天才だから？","ENG":"Because you're a genius?","TWN":"因為你是天才？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"틀린 말은 아니지만, 하담 씨의 도움도 컸죠.","JPN":"間違ってはいませんが、カタンさんの助けが大きかったです。","ENG":"That's not wrong, but Ha Dam's help has been huge too.","TWN":"雖然這句話也沒有錯，不過夏垣幫了我很大的忙。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"학자들이 으레 그렇다시피 말이 안 통할까 걱정부터 했었는데- 척하면 척이었거든요.","JPN":"学者にありがちな、話の通じない人だったらどうしようっていう心配が先立っていたけれど……以心伝心でしたからね。","ENG":"I was worried at first that we wouldn't be able to communicate, as is often the case with scholars, but he understood everything right away.","TWN":"我原本還擔心學者們會很難溝通－結果卻非常合拍。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"신기하지 않아? 당신이랑 말이 통하는 사람이 있다니.","JPN":"不思議だと思わない？　あなたと話の通じる人がいるなんて。","ENG":"Isn't it amazing? That there's actually someone who understands you.","TWN":"真神奇耶？居然有人能和你溝通。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"하지만, 그런 날도 이젠 얼마 안 남았어요.","JPN":"ですが、そんな日々ももうすぐ終わります。","ENG":"But there isn't much time left for days like that now.","TWN":"不過那樣的日子也快結束了。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"<color=#ffd34c>대.우.물</color>이 완성되면, 그분들은 아주 먼 과거로 도약할 테고...","JPN":"<color=#ffd34c>大・イ・ド</color>が完成すれば、あの方たちは遠い過去に跳躍するでしょうし……","ENG":"Once the <color=#ffd34c>Great Well</color> is complete, they'll be making a jump into a very distant past...","TWN":"等<color=#ffd34c>大井</color>完成後，那些人會跳躍到非常遙遠的過去……"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"...오늘날과 연결된 터널이 닫히면서, 그 사람들과 만났던 우리의 기억과 흔적은 언제 그랬냐는 듯 사라지게 되겠지.","JPN":"……今日に繋がったトンネルは閉ざされて、私たちの中に残る、あの人たちと出会った記憶と痕跡は跡形もなく消えるわね。","ENG":"...And once the tunnel connected to the present closes, our memories and traces of having met those people will vanish as if none of it had ever happened.","TWN":"……而與今天相連的通道關閉後，我們與他們相遇的記憶與痕跡，也會像從未存在過般消失。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그래도 괜찮지 않아?","JPN":"でも、それでもいいと思わない？","ENG":"Even so, isn't that fine?","TWN":"不過這樣也沒關係吧？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"우리가 기억 못해도 미래는 변함없이 거기에 있으니까.","JPN":"私たちが忘れてしまっても、未来は変わらずそこにあるんだし。","ENG":"Even if we can't remember, the future will still remain there unchanged.","TWN":"就算我們不記得，未來依然會存在。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"가끔은 당신이 나보다 어려운 말을 한다니까요.","JPN":"あなたはときどき俺より難しい言葉を使う。","ENG":"Sometimes you say things that are even harder to understand than mine.","TWN":"有時候你說的話比我還難懂。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"이로서 가동 준비는 차질 없이 마쳤네.","JPN":"これで稼働準備はつつがなく終わった。","ENG":"We have now finished all preparations for operation without issue.","TWN":"啟動準備已經全部完成了。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"주한과 관리국 기술부 일동에게 감사를 표하지.","JPN":"シスイと管理局技術部の皆に礼を言おう。","ENG":"I offer my gratitude to Joo Han and all personnel of the Administration's technical department.","TWN":"感謝周翰與管理局技術部。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"덕분에 값진 경험을 했습니다...","JPN":"おかげで貴重な経験ができました……","ENG":"Thanks to you, this has been a valuable experience...","TWN":"我原本想說這是非常珍貴的經驗……"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"라고 말하고 싶지만, 어차피 사라질 기억이라면 무슨 말을 해야 좋을지 모르겠군요.","JPN":"と言いたいところですが、どうせ消えてしまう記憶ですし、何を話せばいいのやら。","ENG":"Or that's what I'd like to say, but if the memory is going to disappear anyway, I'm not sure what words would be best.","TWN":"但如果這些記憶終究會消失，我也不知道該說什麼才好了。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"자네는 용혈이 무엇인지 알고 있나?","JPN":"そなたは龍血がどういうものか知っているか？","ENG":"Do you know what Dragon Blood is?","TWN":"你知道什麼是龍血嗎？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"대강은요.","JPN":"だいたいは。","ENG":"Roughly.","TWN":"大概知道。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"어릴 적 고모님께서 사주를 봐주셨는데, 오래 살 팔자는 못된다더군요.","JPN":"小さい頃おばさんに占ってもらいましたが、長生きはできないと言われました。","ENG":"When I was little, my aunt once had my fortune read and said I wasn't fated to live a long life.","TWN":"小時候姑姑幫我算過命，她說我不是長壽的命。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"연화 씨가 품은 용혈이 어떤 힘인지 알고 있으니, 아마도 그런 이유겠죠.","JPN":"レンカさんの持つ龍血がどんな力なのか分かっていますので、たぶんそんな理由でしょう。","ENG":"Since I know what kind of power Yeonhwa's Dragon Blood contains, that's probably why.","TWN":"因為我知道蓮華體內的龍血擁有怎樣的力量，大概也是這個原因吧。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"그럼에도, 그 마음은 바뀌지 않은 건가?","JPN":"それでも、気持ちに変わりはないのか？","ENG":"Even so, your heart hasn't changed?","TWN":"即使如此，你的想法也沒有改變嗎？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"일단은 저도 기술자니까요. 남들이 안된다고 해서 포기할 성격은 못 됩니다.","JPN":"一応は俺も技術者なので。他人からダメと言われたからといって諦められる性格ではないんですよ。","ENG":"Well, I am a technician too. I'm not the type to give up just because others say it can't be done.","TWN":"畢竟我也是技術人員，不會因為別人說不行就放棄。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"설령 그 끝에 기다리는 것이 연옥이라 해도... 우리가 함께 지나온 길이 소중하지 않았다고 말하진 않을 거에요.","JPN":"たとえその果てに待つものが煉獄だとしても……俺たちが共に過ごした時間が無駄だったとは言わないと思います。","ENG":"Even if what waits at the end is purgatory... I'd never say the path we walked together wasn't precious.","TWN":"就算最後等待我們的是煉獄……我也不會說我們一起經歷過的歷程毫無意義。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"그렇군.","JPN":"そうか。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ENGINEER_NPC_ADMIN_NULL","text":{"KOREA":"20년 간극으로 추정되는 시간축 좌표로부터 우물 입구를 관측...!","JPN":"20年の間隙と推定される時間軸の座標から、イドの入口を観測……！","ENG":"Observing the Well's entrance from time-axis coordinates estimated to be twenty years apart...!","TWN":"觀測到來自約20年前時間軸座標的井入口……！"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ENGINEER_NPC_ADMIN_NULL","text":{"KOREA":"충전된 허수 에너지를 이용해 차원터널을 연결합니다!","JPN":"充電済みの虚数エネルギーを利用して次元トンネルを連結します！","ENG":"Using the charged Imaginary Energy, we are connecting the dimensional tunnel!","TWN":"利用充能的虛空能量連接次元隧道！"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"이론대로라면, 현재와 미래를 잇는 이 증폭터널이 클리파 에너지의 저장고가 되어 우물의 과부하 한계를 무한대로 끌어올려 줄 걸세.","JPN":"理論どおりなら、現在と未来を繋ぐこの増幅トンネルがクリファエネルギーの貯蔵庫となり、イドの過負荷の限界を無限大にしてくれるはずだ。","ENG":"According to theory, this amplification tunnel linking the present and future will become a reservoir for Qlipha energy, raising the Well's overload limit to infinity.","TWN":"按照理論，連接現在與未來的這條增幅隧道會成為逆卡巴拉能量的儲存庫，將井的負荷上限推到無限。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"그 무한대의 에너지로 초광역터널을 열어 20년 전이 아닌, 태곳적으로 갈 수 있게 되는 것이지.","JPN":"その無限大のエネルギーをもって超広域トンネルを開き、20年前ではなく太古に行けるようになる。","ENG":"And with that infinite energy, we'll be able to open a hyperwide tunnel and travel not twenty years into the past, but to primordial times.","TWN":"再用這無限的能量打開超廣域隧道，就能前往不只20年，而是更遙遠的太古時代。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"그러면, 마왕 타기리온이 오래 전 시간을 멈춰준 세계에도 다다를 수 있겠군요.","JPN":"それなら魔王タギリオンが大昔に時間を止めた世界にもたどり着けそうですね。","ENG":"Then that means you'll be able to reach the world where Demon Lord Thagirion stopped time long ago.","TWN":"那樣一來，我們也能抵達魔王塔基里翁曾在很久以前凍結時間的那個世界。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"저희도 여러분과 함께, 전력으로 토벌을 돕겠습니다.","JPN":"俺たちも皆さんと共に、全力で討伐を手伝います。","ENG":"We'll join you as well and assist in the subjugation with everything we have.","TWN":"到時候，我們也會與各位並肩作戰，全力討伐她。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"아니, 자네들은 우리가 초광역터널을 여는대로 연결을 끊게.","JPN":"いや、そなたらは我らが超広域トンネルを開き次第連結を切断するのだ。","ENG":"No. The moment we open the hyperwide tunnel, you must sever the connection.","TWN":"不，你們在我們打開超廣域隧道的瞬間就切斷連結吧。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"어째서죠? 그렇게 했다간...!","JPN":"どうしてですか？　そうなると……！","ENG":"Why? If we do that...!","TWN":"為什麼？那樣一來……！"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"두 시간선이 연결된 채로 초광역터널을 열면, 마왕에게 과거로 통하는 길을 열어주는 꼴이 되고 말아.","JPN":"2つの時間線が繋がったまま超広域トンネルを開くと、魔王に過去への通路を開けてやることになってしまう。","ENG":"If we open a hyperwide tunnel while the two timelines remain connected, we'd be opening a path into the past for the Demon Lord.","TWN":"如果在兩條時間線仍然相連的情況下打開超廣域隧道，就等於替魔王打開一條通往過去的道路。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"우리는 미래를 구하기 위해 온 것이지, 과거를 희생시키려고 온 게 아니니까.","JPN":"我らは未来を救うために来たのであって、そのために過去を犠牲にしてはならないからな。","ENG":"We came here to save the future, not to sacrifice the past.","TWN":"我們是為了拯救未來而來，不是為了犧牲過去。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"정말, 저희가 없어도 괜찮으시겠어요?","JPN":"本当に、私たちがいなくても大丈夫ですか？","ENG":"Will you truly be all right without us?","TWN":"真的……就算沒有我們也沒問題嗎？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"...걱정 마라.","JPN":"……心配するな。","ENG":"...Don't worry.","TWN":"……別擔心。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"용혈에 통달한 인재는 미래에도 있으니 말이다.","JPN":"龍血に精通した人材は未来にもいるからな。","ENG":"There are those in the future as well who have mastered Dragon Blood.","TWN":"在未來，依然有精通龍血的人才。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"무슨 말씀인지 알겠어요, 스승님.","JPN":"おっしゃりたいことは理解しました、師匠。","ENG":"I understand what you mean, Master.","TWN":"我明白您的意思了，師父。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ENGINEER_NPC_ADMIN_NULL","text":{"KOREA":"...양방향 증폭터널 연결 확인! 대우물 진입로 활성화!","JPN":"……両方向増幅トンネルの連結を確認！　大イドの進入路活性化！","ENG":"...Bidirectional amplification tunnel connection confirmed! Great Well entry path activated!","TWN":"……雙向增幅隧道連接確認！大井入口啟動！"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"현재와 미래를 잇는 증폭터널은 1시간 뒤 폐쇄, 초광역터널은 증폭터널이 폐쇄되는 동시에 여러분이 온 현실과 연결될 겁니다.","JPN":"現在と未来を繋ぐ増幅トンネルは1時間後に閉鎖、超広域トンネルは増幅トンネルの閉鎖と同時に皆さんが来た現実と繋がります。","ENG":"The amplification tunnel linking the present and future will close in one hour, and the hyperwide tunnel will connect to the reality you came from the moment the amplification tunnel closes.","TWN":"連接現在與未來的增幅隧道將在1小時後關閉，超廣域隧道會在增幅隧道關閉的同時，與你們出發的現實世界連接。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"초광역터널이 지금처럼 허수 에너지를 지속적으로 공급 받는 한 영구적으로 유지할 수 있을 겁니다만...","JPN":"超広域トンネルに虚数エネルギーが持続的に供給されるかぎり、永続的に維持できるはずですが……","ENG":"As long as the hyperwide tunnel continues receiving a constant supply of Imaginary Energy like it is now, it should be able to remain open permanently, but...","TWN":"只要超廣域隧道能像現在這樣持續獲得虛空能量，理論上就能永久維持……"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"터널이 얼마나 버틸지는 의미가 없어. 그전에 현실이 먼저 허수에 삼켜지고 말 테니.","JPN":"トンネルがどれだけ持つかは意味がない。その前に現実が虚数に飲まれるだろうからな。","ENG":"It doesn't matter how long the tunnel can last. Before that, reality itself will be swallowed by Imaginary Energy.","TWN":"其實隧道能撐多久沒有意義。在那之前，現實就會先被虛空吞沒。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"...역시 그렇군요.","JPN":"……やはりそうですか。","ENG":"...I thought as much.","TWN":"……果然如此。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"여러분이 타고 온 우물에 충분한 허수 에너지가 공급되고 있다는 건, 현실에 그만큼 막대한 클리파가 쏟아져 들어오고 있다는 뜻일 테니까요.","JPN":"皆さんが通ってきたイドに十分な虚数エネルギーが供給されているということは、その分現実に莫大なクリファが注ぎ込まれているという意味でしょうからね。","ENG":"If enough Imaginary Energy is being supplied to the Well you arrived in, then that means an enormous amount of Qlipha is pouring into reality.","TWN":"你們所乘坐的井能獲得如此充足的虛空能量，代表現實世界正湧入同樣龐大的逆卡巴拉能量。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"잘 가세요. 펜릴 소대 여러분.","JPN":"さようなら、フェンリル小隊の皆さん。","ENG":"Safe travels, Fenrir Squad.","TWN":"一路順風，芬里爾小隊。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"미래를 부탁드려요.","JPN":"未来を頼みますね。","ENG":"Please take care of the future.","TWN":"未來就拜託你們了。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"...응. 미래는 맡겨둬.","JPN":"……うん。未来は任せて。","ENG":"...Yeah. Leave the future to us.","TWN":"……嗯，未來就交給我們。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"과거... 아니, 지금은 당신들에게 맡길게.","JPN":"過去……いや、現在はあなたたちに任せるよ。","ENG":"The past– No, the present belongs to you now.","TWN":"過去……不，現在就交給你們。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"그럼, 초광역터널을 열기에 앞서 우린 현실로 복귀를...","JPN":"では超広域トンネルを開く前に、我らは現実に復帰を……","ENG":"Then before we open the hyperwide tunnel, we'll return to reality...","TWN":"那麼，在打開超廣域隧道前，我們先返回現實……"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_COFFIN_LASER_MAIN"},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"...음?","JPN":"……ん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"뭐지?","JPN":"なんだ？","ENG":"What is it?","TWN":"怎麼回事？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"증폭터널에 다수의 차원균열이 감지됐다고?","JPN":"増幅トンネルに多数の次元亀裂が感知された？","ENG":"You're saying multiple dimensional rifts have been detected in the amplification tunnel?","TWN":"增幅隧道檢測到大量次元裂縫？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이 기운은...","JPN":"この気配は……","ENG":"This presence...","TWN":"這股氣息是……"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다들 우물에서 멀리 떨어져라!","JPN":"みんな、イドから離れろ！","ENG":"Everyone, get away from the Well!","TWN":"所有人立刻離開井！"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"증폭터널의 에너지 순환이 완전히 끊겼습니다.","JPN":"増幅トンネルのエネルギー循環が完全に断たれてしまいました。","ENG":"The energy circulation in the amplification tunnel has been completely cut off.","TWN":"增幅隧道的能量循環完全中斷了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"설마, 저쪽의 우물이 파괴된 걸까요?","JPN":"まさか、あちらのイドが破壊されたんでしょうか？","ENG":"Could it be... was the Well on the other side destroyed?","TWN":"難道……另一邊的井被破壞了嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"시간과 시간 사이를 잇는 터널이 붕괴했다면, 우리가 이곳에 멀쩡히 남아있진 못할 걸세.","JPN":"時間と時間を繋ぐトンネルが崩壊したのなら、我らがここに無事に残ってはいまい。","ENG":"If the tunnel linking one time to another had collapsed, we wouldn't still be here unharmed.","TWN":"如果連接時間與時間的隧道真的崩塌，我們也不可能安然無恙待在這裡。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"아무래도... 터널 자체를 무언가가 틀어 막고 있는 것 같군.","JPN":"どうやら……トンネル自体を何かが塞いでいるようだ。","ENG":"It seems... something is physically blocking the tunnel itself.","TWN":"看來……似乎有什麼東西堵住了隧道。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"와앗, 우물에서 뭐가 튀어나왔어요!","JPN":"わわっ、イドから何かが飛び出てきました！","ENG":"Whoa! Something just burst out of the Well!","TWN":"哇，井裡有東西跑出來了！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저게 뭐죠? 사람은 아닌 것 같은데...","JPN":"あれ、何ですか？　人じゃないみたいですけど……","ENG":"What is that? It doesn't look human...","TWN":"那是什麼？看起來不像人……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"인형...? 저런 게 터널 안에 있던 거야?","JPN":"人形……？　あんなものがトンネルの中にいたの？","ENG":"A doll...? Something like that was inside the tunnel?","TWN":"人偶……？那種東西原本就在隧道裡嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"타기리온의 공작이군.","JPN":"タギリオンの仕業だな。","ENG":"So this is Thagirion's doing.","TWN":"是塔基里翁的手段。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어쩐지 한동안 잠잠하더라니.","JPN":"しばらく大人しくしていると思ったら。","ENG":"I was wondering why things had been so quiet for a while.","TWN":"難怪最近一直這麼安靜。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"현실 바깥에선 마왕도 힘의 제약을 받지 않으니까. 차원 간 통로를 노린 것도 그런 이유겠지.","JPN":"現実の外では魔王の力も制約を受けないからな。次元間通路を狙ったのもそのためだろう。","ENG":"Outside reality, even a Demon Lord is not restricted in power. That's probably why she targeted the passage between dimensions.","TWN":"在現實之外，魔王不會受到力量限制。她會盯上次元通道，大概也是這個原因。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럼 저희가 돌아갈 방법도 막힌 걸까요? 이제 어쩌죠?","JPN":"じゃあ、私たちが帰る方法もなくなっちゃったんですか？　どうしましょう？","ENG":"Then does that mean our way back is blocked too? What do we do now?","TWN":"那我們回去的路也被堵住了嗎？現在該怎麼辦？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"...우선 저것들부터 치우고 논의하지.","JPN":"……話し合うのは、あれを片付けてからだな。","ENG":"...First, let's clear those things out. Then we'll discuss it.","TWN":"……先清掉那些東西再說。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};